import { UMB_ACTION_EVENT_CONTEXT } from "@umbraco-cms/backoffice/action";
import type {
  UmbControllerHost,
  UmbControllerHostElement,
} from "@umbraco-cms/backoffice/controller-api";
import { UmbRequestReloadStructureForEntityEvent } from "@umbraco-cms/backoffice/entity-action";
import { UmbObjectState } from "@umbraco-cms/backoffice/observable-api";
import type { UmbDetailRepository } from "@umbraco-cms/backoffice/repository";
import type { Component } from "@umbraco-cms/backoffice/router";
import type { UmbSubmittableWorkspaceContext } from "@umbraco-cms/backoffice/workspace";
import { UmbSubmittableWorkspaceContextBase } from "@umbraco-cms/backoffice/workspace";
import { FORMS_CONTEXT } from "@umbraco-forms/context";
import type {
  FormSecurityForGroup,
  FormSecurityForUser,
} from "@umbraco-forms/generated";
import type { PackagePermissionsSecurityBase } from '../entities.js';

export interface FormsSecurityRepositoryConstructor<ItemType> {
  new (host: UmbControllerHost): UmbDetailRepository<ItemType>;
}

export interface FormsSecurityWorkspaceContext {
  setProperty(alias: keyof PackagePermissionsSecurityBase | "startFolderIds", value: unknown): void;
  toggleFormSecurityAccess(formId: string): void;
  setFormSecurityAccess(formId: string, value: boolean): void;
}

export class FormsSecurityWorkspaceBaseContext<
    SecurityType extends FormSecurityForGroup | FormSecurityForUser
  >
  extends UmbSubmittableWorkspaceContextBase<SecurityType>
  implements UmbSubmittableWorkspaceContext, FormsSecurityWorkspaceContext
{
  protected _data = new UmbObjectState<SecurityType | undefined>(undefined);

  #repository: UmbDetailRepository<SecurityType>;

  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  #getDataPromise?: Promise<any>;

  #entityType: string;

  readonly data = this._data.asObservable();
  readonly unique = this._data.asObservablePart((data) => data?.unique);
  readonly name = this._data.asObservablePart((data) => data?.name);
  readonly id = this._data.asObservablePart((data) => data?.unique);

  constructor(
    host: UmbControllerHostElement,
    workspaceAlias: string,
    entityType: string,
    repository: FormsSecurityRepositoryConstructor<SecurityType>,
    component: Component,
  ) {
    super(host, workspaceAlias);

    this.#repository = new repository(this);
    this.#entityType = entityType;
    
    this.routes.setRoutes([
        {
          path: "edit/:unique",
          component,
          setup: (_component, info) => {
            const unique = info.match.params.unique;
            this.load(unique);
          },
        },
      ]);
  }

  getData() {
    return this._data.getValue();
  }

  getUnique() {
    return this.getData()?.unique || "";
  }

  getEntityType(): string {
    return this.#entityType;
  }

  setProperty(alias: keyof PackagePermissionsSecurityBase | "startFolderIds", value: unknown) {
    if (!this._data.value) return;
    this._data.update({ [alias]: value } as Partial<SecurityType>);
  }

  async load(id: string) {
    this.#getDataPromise = this.#repository?.requestByUnique(id);
    const { data } = await this.#getDataPromise;

    if (data) {
      this.setIsNew(false);
      this._data.update(data);
    }
  }

  async submit(): Promise<void> {
    if (!this._data.value) return;
    if (!this._data.value.unique) return;

    const eventContext = await this.getContext(UMB_ACTION_EVENT_CONTEXT);

    await this.#repository?.save(this._data.value);

    // after saving ensure the global forms context fetches the new value
    // to avoid having to refresh to see updated values
    const formsContext = await this.getContext(FORMS_CONTEXT);
    await formsContext.getUserSecurity();

    const event = new UmbRequestReloadStructureForEntityEvent({
      unique: this.getUnique()!,
      entityType: this.getEntityType(),
    });
    eventContext.dispatchEvent(event);
  }

  toggleFormSecurityAccess(formId: string) {
    if (!this._data.value) return;

    const formsSecurity = this._data.value.formsSecurity.map((r) => ({
      ...r,
      ...(r.form === formId && {
        hasAccess: !r.hasAccess,
      }),
    }));

    this._data.update({ formsSecurity } as Partial<SecurityType>);
  }

  setFormSecurityAccess(formId: string, value: boolean) {
    if (!this._data.value) return;

    const formsSecurity = this._data.value.formsSecurity.map((r) => ({
      ...r,
      ...(r.form === formId && {
        hasAccess: value,
      }),
    }));

    this._data.update({ formsSecurity } as Partial<SecurityType>);
  }

  destroy() {
    this._data.destroy();
  }
}
